     1→/// Sync status enumeration representing the current state of synchronization
     2→enum SyncStatus {
     3→  /// Idle - No sync activity, ready to sync
     4→  idle,
     5→
     6→  /// Syncing - Currently synchronizing data
     7→  syncing,
     8→
     9→  /// Success - Last sync completed successfully
    10→  success,
    11→
    12→  /// Failed - Last sync failed and needs retry
    13→  failed,
    14→
    15→  /// Pending - Changes waiting to be synced
    16→  pending,
    17→}
    18→
    19→/// Extension on SyncStatus for utility methods
    20→extension SyncStatusExtension on SyncStatus {
    21→  /// Whether this status represents an active sync operation
    22→  bool get isActive => this == SyncStatus.syncing;
    23→
    24→  /// Whether this status represents a completed sync
    25→  bool get isCompleted =>
    26→      this == SyncStatus.success || this == SyncStatus.failed;
    27→
    28→  /// Whether this status represents an error state
    29→  bool get isError => this == SyncStatus.failed;
    30→
    31→  /// Whether sync is available (not currently syncing)
    32→  bool get canSync => this != SyncStatus.syncing;
    33→
    34→  /// User-friendly display name
    35→  String get displayName {
    36→    switch (this) {
    37→      case SyncStatus.idle:
    38→        return 'Ready';
    39→      case SyncStatus.syncing:
    40→        return 'Syncing...';
    41→      case SyncStatus.success:
    42→        return 'Synced';
    43→      case SyncStatus.failed:
    44→        return 'Sync Failed';
    45→      case SyncStatus.pending:
    46→        return 'Pending';
    47→    }
    48→  }
    49→
    50→  /// Icon code point for Material Icons
    51→  int get iconCodePoint {
    52→    switch (this) {
    53→      case SyncStatus.idle:
    54→        return 0xe24e; // sync
    55→      case SyncStatus.syncing:
    56→        return 0xe625; // sync (animated)
    57→      case SyncStatus.success:
    58→        return 0xe876; // check_circle
    59→      case SyncStatus.failed:
    60→        return 0xe000; // error
    61→      case SyncStatus.pending:
    62→        return 0xe923; // schedule
    63→    }
    64→  }
    65→}
