     8→class SharedPrefsTravelOperationRepository
     9→    implements TravelOperationRepository {
    10→  final SharedPreferences _prefs;
    11→  static const String _keyPrefix = 'travel_op_';
    12→  static const String _pendingOpsKey = 'pending_ops';
    13→
    14→  SharedPrefsTravelOperationRepository(this._prefs);
    15→
    16→  @override
    17→  Future<void> saveOperation(BaseTravelOperation operation) async {
    18→    final String opKey = '$_keyPrefix${operation.id}';
    19→    final String opJson = jsonEncode(operation.toJson());
    20→
    21→    await _prefs.setString(opKey, opJson);
    22→
    23→    // Update pending operations list
    24→    final List<String> pendingOps = _prefs.getStringList(_pendingOpsKey) ?? [];
    25→    if (!pendingOps.contains(operation.id)) {
    26→      pendingOps.add(operation.id);
    27→      await _prefs.setStringList(_pendingOpsKey, pendingOps);
    28→    }
    29→  }
    30→
    31→  @override
    32→  Future<List<BaseTravelOperation>> getPendingOperations() async {
    33→    final List<String> pendingOps = _prefs.getStringList(_pendingOpsKey) ?? [];
    34→    final List<BaseTravelOperation> operations = [];
    35→
    36→    for (final String opId in pendingOps) {
    37→      final String? opJson = _prefs.getString('$_keyPrefix$opId');
    38→      if (opJson != null) {
    39→        try {
    40→          final Map<String, dynamic> opMap = jsonDecode(opJson);
    41→          final operation = _deserializeOperation(opMap);
    42→          if (operation != null) {
    43→            operations.add(operation);
    44→          }
    45→        } catch (e) {
    46→          // Log error and continue
    47→          print('Error deserializing operation $opId: $e');
    48→        }
    49→      }
    50→    }
    51→
    52→    return operations;
    53→  }
    54→
    55→  @override
    56→  Future<List<BaseTravelOperation>> getOperationsByType(String type) async {
    57→    final List<BaseTravelOperation> allOps = await getPendingOperations();
    58→    return allOps.where((op) => op.type == type).toList();
    59→  }
    60→
    61→  @override
    62→  Future<void> deleteOperation(String id) async {
    63→    final String opKey = '$_keyPrefix$id';
    64→    await _prefs.remove(opKey);
    65→
    66→    // Remove from pending operations list
    67→    final List<String> pendingOps = _prefs.getStringList(_pendingOpsKey) ?? [];
    68→    pendingOps.remove(id);
    69→    await _prefs.setStringList(_pendingOpsKey, pendingOps);
    70→  }
    71→
    72→  @override
    73→  Future<List<BaseTravelOperation>> getOperationsForTrip(String tripId) async {
    74→    final List<BaseTravelOperation> allOps = await getPendingOperations();
    75→    return allOps.where((op) {
    76→      final Map<String, dynamic> json = op.toJson();
    77→      return json['tripId'] == tripId;
    78→    }).toList();
    79→  }
    80→
    81→  @override
    82→  Future<void> clearProcessedOperations() async {
    83→    final List<String> pendingOps = _prefs.getStringList(_pendingOpsKey) ?? [];
    84→
    85→    // Remove all operation data
    86→    for (final String opId in pendingOps) {
    87→      await _prefs.remove('$_keyPrefix$opId');
    88→    }
    89→
    90→    // Clear pending operations list
    91→    await _prefs.setStringList(_pendingOpsKey, []);
    92→  }
